esqlQuery.esql:
FROM metrics-postgresqlreceiver.otel-*
// Commits and rollbacks are monotonic counters per database
| WHERE postgresql.commits IS NOT NULL OR postgresql.rollbacks IS NOT NULL
| EVAL commits_val = TO_DOUBLE(postgresql.commits), rollbacks_val = TO_DOUBLE(postgresql.rollbacks)
| STATS total_commits = SUM(commits_val), total_rollbacks = SUM(rollbacks_val) BY service.instance.id, postgresql.database.name
// Minimum transaction volume to avoid noisy low-traffic databases
| WHERE total_commits > 10
// Rollback rate > 1% indicates application errors or contention; adjust threshold as needed
| EVAL rollback_rate_pct = CASE(total_commits > 0, ROUND(total_rollbacks / (total_commits + total_rollbacks) * 100.0, 2), 0.0)
| WHERE rollback_rate_pct > 1.0
